const o=document.getElementById("scroll-progress");o&&window.addEventListener("scroll",()=>{const e=window.scrollY,t=document.documentElement.scrollHeight-window.innerHeight,s=t>0?e/t*100:0;o.style.width=s+"%"},{passive:!0});const i=document.querySelectorAll(".reveal");if(i.length&&"IntersectionObserver"in window){const e=new IntersectionObserver(t=>{t.forEach(s=>{s.isIntersecting&&(s.target.classList.add("visible"),e.unobserve(s.target))})},{threshold:.12});i.forEach(t=>e.observe(t))}else i.forEach(e=>e.classList.add("visible"));const n=document.getElementById("menu-toggle"),r=document.getElementById("mobile-menu");n?.addEventListener("click",()=>{const e=r?.classList.toggle("open");n.setAttribute("aria-expanded",String(e)),r?.setAttribute("aria-hidden",String(!e)),n.setAttribute("aria-label",e?"Cerrar menú":"Abrir menú")});r?.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{r.classList.remove("open"),n?.setAttribute("aria-expanded","false"),r.setAttribute("aria-hidden","true")})});
